export function renderIcon(name, options = {}) {
  const def = iconDefinitions[name] || { path: name, inset: "0%", viewBox: "0 0 24 24" };
  const path = svgPaths[def.path] || svgPaths[name];
  if (!path) return "";

  const {
    size = options.size || 24,
    color = options.color || "currentColor",
    inset = options.inset || def.inset,
    viewBox = options.viewBox || def.viewBox
  } = options;

  const cssInset = inset.replace(/_/g, " ");

  return `
    <div class="icon-frame" style="overflow: clip; position: relative; flex-shrink: 0; width: ${size}px; height: ${size}px;">
      <div style="position: absolute; inset: ${cssInset};">
        <svg style="position: absolute; display: block; width: 100%; height: 100%;" fill="none" preserveAspectRatio="none" viewBox="${viewBox}">
          <path d="${path}" fill="${color}" />
        </svg>
      </div>
    </div>
  `;
}
